1	#!/usr/bin/env bun
2	/**
3	 * tasks.ts — Task CRUD: add, complete, set status, move, link, unlink, list, summary
4	 *
5	 * CLI:
6	 *   bun src/tools/obsidian/tasks.ts add --content <text> [--parent <num>] [--date <date>]
7	 *   bun src/tools/obsidian/tasks.ts complete --task <num|text> [--date <date>]
8	 *   bun src/tools/obsidian/tasks.ts status --task <num|text> --status <status> [--date <date>]
9	 *   bun src/tools/obsidian/tasks.ts move --task <num|text> [--to-date <date>] [--under <num>] [--to-top] [--date <date>]
10	 *   bun src/tools/obsidian/tasks.ts link --task <num|text> --doc <path> [--date <date>]
11	 *   bun src/tools/obsidian/tasks.ts unlink --task <num|text> --doc <path> [--date <date>]
12	 *   bun src/tools/obsidian/tasks.ts list [--date <date>]
13	 *   bun src/tools/obsidian/tasks.ts summary [--date <date>]
14	 */
15	
16	import { z } from "zod";
17	import type { ToolDefinition } from "../../registry/types.js";
18	import { parseDate } from "../../libs/dates.js";
19	import { readNote, writeNote, noteExists } from "../../libs/vault.js";
20	import {
21	  parse,
22	  serialize,
23	  findSection as omFindSection,
24	  sectionBodyText,
25	  findTask,
26	  listTasks as omListTasks,
27	  addTask as omAddTask,
28	  setTaskStatus as omSetTaskStatus,
29	  completeTask as omCompleteTask,
30	  moveTask as omMoveTask,
31	  linkDoc as omLinkDoc,
32	  unlinkDoc as omUnlinkDoc,
33	  getNextTaskId,
34	  carryForward as omCarryForward,
35	  appendToSection as omAppendToSection,
36	} from "../../libs/obsidian-md/index.js";
37	import type { Document, Task, TaskStatus } from "../../libs/obsidian-md/types.js";
38	import { STATUS_TO_CHAR } from "../../libs/obsidian-md/types.js";
39	import { confirm, notFound, noMatch, heading, counts, taskFallback, formatTaskLines } from "../../libs/format.js";
40	import { initializeDailyWithCarryForward, countItems, flag, hasFlag } from "./shared.js";
41	
42	// ── Fuzzy task match helper ─────────────────────────────────────────────
43	
44	function findTaskByQuery(doc: Document, query: string): Task | undefined {
45	  const cleanQuery = query.replace(/^\[|\]$/g, '');
46	  const numberMatch = /^\d+(\.\d+)*$/.test(cleanQuery);
47	
48	  const allTasks: Task[] = [];
49	  for (const node of doc.preamble) {
50	    if (node.type === 'task') {
51	      const t = node as Task;
52	      allTasks.push(t);
53	      for (const sub of t.subtasks) allTasks.push(sub);
54	    }
55	  }
56	  for (const section of doc.sections) {
57	    for (const node of section.body) {
58	      if (node.type === 'task') {
59	        const t = node as Task;
60	        allTasks.push(t);
61	        for (const sub of t.subtasks) allTasks.push(sub);
62	      }
63	    }
64	  }
65	
66	  if (numberMatch) {
67	    return allTasks.find(t => t.id === cleanQuery);
68	  }
69	
70	  const queryLower = cleanQuery.toLowerCase();
71	  let best: Task | undefined;
72	  let bestLen = Infinity;
73	  for (const t of allTasks) {
74	    const contentLower = t.content.toLowerCase();
75	    if (contentLower.includes(queryLower) && t.content.length < bestLen) {
76	      best = t;
77	      bestLen = t.content.length;
78	    }
79	  }
80	  return best;
81	}
82	
83	// ── Pending tasks list for fallback messages ────────────────────────────
84	
85	function getPendingList(doc: Document): string[] {
86	  const tasksSection = omFindSection(doc, 'Tasks');
87	  if (!tasksSection) return [];
88	  const pending: string[] = [];
89	  for (const node of tasksSection.body) {
90	    if (node.type === 'task') {
91	      const t = node as Task;
92	      if (t.isLabel) continue;
93	      if (t.status === 'todo') pending.push(`- ${t.content}`);
94	      for (const sub of t.subtasks) {
95	        if (sub.status === 'todo') pending.push(`  - ${sub.content}`);
96	      }
97	    }
98	  }
99	  return pending;
100	}
101	
102	// ── Ensure daily note exists ────────────────────────────────────────────
103	
104	function ensureDaily(date: string): string {
105	  const path = `daily/${date}.md`;
106	  if (!noteExists(path)) initializeDailyWithCarryForward(date);
107	  return path;
108	}
109	
110	// ── Add task ────────────────────────────────────────────────────────────
111	
112	export function addTask(args: { date?: string; content: string; parent?: string }): string {
113	  const date = parseDate(args.date);
114	  const path = ensureDaily(date);
115	  const content = readNote(path)!;
116	  const doc = parse(content);
117	
118	  if (args.parent) {
119	    const cleanParent = args.parent.replace(/^\[|\]$/g, '');
120	    const parentTask = findTask(doc, cleanParent);
121	    if (!parentTask) return `No task numbered [${cleanParent}] found.`;
122	    const updated = omAddTask(doc, args.content, cleanParent);
123	    // Find the new subtask to get its ID
124	    const newParent = findTask(updated, cleanParent)!;
125	    const newSub = newParent.subtasks[newParent.subtasks.length - 1];
126	    writeNote(path, serialize(updated));
127	    return confirm(`Sub-task added under [${cleanParent}]`, date, args.content);
128	  }
129	
130	  const newId = getNextTaskId(doc);
131	  const updated = omAddTask(doc, args.content);
132	  writeNote(path, serialize(updated));
133	  return confirm(`Task [${newId}] added`, date, args.content);
134	}
135	
136	// ── Complete task ───────────────────────────────────────────────────────
137	
138	export function completeTask(args: { date?: string; task: string }): string {
139	  const date = parseDate(args.date);
140	  const path = `daily/${date}.md`;
141	  if (!noteExists(path)) return notFound("daily note", date);
142	  const content = readNote(path)!;
143	  const doc = parse(content);
144	  const task = findTaskByQuery(doc, args.task);
145	
146	  if (!task) {
147	    const pending = getPendingList(doc);
148	    if (pending.length === 0) return notFound("pending tasks", date);
149	    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
150	  }
151	
152	  // Labels have no checkbox — can't be completed
153	  if (task.isLabel) return `Task [${task.id}] is a group label and cannot be completed.`;
154	
155	  // Only toggle [ ] tasks
156	  if (task.status !== 'todo') {
157	    const pending = getPendingList(doc);
158	    if (pending.length === 0) return notFound("pending tasks", date);
159	    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
160	  }
161	
162	  const matched = task.content;
163	  const updated = omCompleteTask(doc, task.id);
164	  writeNote(path, serialize(updated));
165	  return confirm("Task completed", date, matched);
166	}
167	
168	// ── Set status ──────────────────────────────────────────────────────────
169	
170	const STATUS_NAMES: Record<TaskStatus, string> = {
171	  in_progress: 'In Progress',
172	  deferred: 'Deferred',
173	  cancelled: 'Cancelled',
174	  urgent: 'Urgent',
175	  question: 'Question',
176	  done: 'Done',
177	  todo: 'Todo',
178	};
179	
180	export function setStatus(args: { date?: string; task: string; status: string }): string {
181	  const marker = STATUS_TO_CHAR[args.status as TaskStatus];
182	  const name = STATUS_NAMES[args.status as TaskStatus];
183	  if (!marker || !name) {
184	    const valid = Object.entries(STATUS_TO_CHAR).map(([k, v]) => `${k} [${v}]`).join(", ");
185	    return `Unknown status "${args.status}". Valid: ${valid}`;
186	  }
187	  const date = parseDate(args.date);
188	  const path = `daily/${date}.md`;
189	  if (!noteExists(path)) return notFound("daily note", date);
190	  const content = readNote(path)!;
191	  const doc = parse(content);
192	  const task = findTaskByQuery(doc, args.task);
193	
194	  if (!task) {
195	    const pending = getPendingList(doc);
196	    if (pending.length === 0) return notFound("tasks", date);
197	    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
198	  }
199	
200	  // Labels have no checkbox — can't change status
201	  if (task.isLabel) return `Task [${task.id}] is a group label and cannot have its status changed.`;
202	
203	  const matched = task.content;
204	  const updated = omSetTaskStatus(doc, task.id, args.status as TaskStatus);
205	  writeNote(path, serialize(updated));
206	  return confirm(`Task [${marker}] ${name}`, date, matched);
207	}
208	
209	// ── Edit task text ──────────────────────────────────────────────────────
210	
211	export function editTask(args: { date?: string; task: string; text: string }): string {
212	  const date = parseDate(args.date);
213	  const path = `daily/${date}.md`;
214	  if (!noteExists(path)) return notFound("daily note", date);
215	  const content = readNote(path)!;
216	  const doc = parse(content);
217	  const task = findTaskByQuery(doc, args.task);
218	
219	  if (!task) {
220	    const pending = getPendingList(doc);
221	    return `${noMatch("task", args.task, date)} ${taskFallback(pending)}`;
222	  }
223	
224	  const matched = task.content;
225	  task.content = args.text;
226	  task.dirty = true;
227	  writeNote(path, serialize(doc));
228	  return `Task updated in ${date}: "${matched}" -> "${args.text}"`;
229	}
