231	// ── Move task ───────────────────────────────────────────────────────────
232	
233	export function moveTask(args: { task: string; date?: string; to_date?: string; under?: string; to_top?: boolean }): string {
234	  const date = parseDate(args.date);
235	  const path = `daily/${date}.md`;
236	  if (!noteExists(path)) return notFound("daily note", date);
237	  const content = readNote(path)!;
238	  const doc = parse(content);
239	
240	  const task = findTaskByQuery(doc, args.task);
241	  if (!task) return `Task "${args.task}" not found in ${date}.`;
242	
243	  const isSubTask = task.indent > 0;
244	  const isLabel = task.isLabel;
245	
246	  // Promote sub-task to top-level
247	  if (args.to_top) {
248	    if (!isSubTask) return `Task "${args.task}" is already top-level.`;
249	    const taskText = task.content;
250	    const newId = getNextTaskId(doc);
251	    const updated = omMoveTask(doc, task.id, { toTop: true });
252	    writeNote(path, serialize(updated));
253	    return `Promoted "${taskText}" to top-level task [${newId}] in ${date}.`;
254	  }
255	
256	  // Nest under a parent
257	  if (args.under) {
258	    const parentNum = args.under.replace(/^\[|\]$/g, '');
259	    if (isSubTask) return `Task "${args.task}" is already a sub-task. Promote it first with to_top, then nest.`;
260	    if (isLabel) return `Cannot nest a group label under another task.`;
261	    const taskText = task.content;
262	    const parentTask = findTask(doc, parentNum);
263	    if (!parentTask) return `Parent task [${parentNum}] not found.`;
264	    const newSubId = getNextTaskId(doc, parentNum);
265	    const updated = omMoveTask(doc, task.id, { under: parentNum });
266	    writeNote(path, serialize(updated));
267	    return `Nested "${taskText}" under [${parentNum}] as [${newSubId}] in ${date}.`;
268	  }
269	
270	  // Move to another date
271	  if (args.to_date) {
272	    const targetDate = parseDate(args.to_date);
273	    const targetPath = `daily/${targetDate}.md`;
274	    if (!noteExists(targetPath)) return `${notFound("daily note", targetDate)} Create it first.`;
275	
276	    const targetContent = readNote(targetPath)!;
277	    const sourceDoc = parse(content);
278	    const targetDoc = parse(targetContent);
279	
280	    // Get task details before mutation
281	    const taskText = task.content;
282	    const taskId = task.id;
283	
284	    // Build the target link
285	    const targetLink = `[[notes/daily/${targetDate}|${targetDate.slice(5)}]]`;
286	    const sourceLink = `[[notes/daily/${date}|${date.slice(5)}]]`;
287	
288	    // Get next task ID in target
289	    const nextId = getNextTaskId(targetDoc);
290	
291	    // Mark source task as deferred with forward link
292	    const mutableSource = parse(content);
293	    const sourceTask = findTask(mutableSource, taskId);
294	    if (sourceTask) {
295	      sourceTask.status = 'deferred';
296	      sourceTask.isStrikethrough = true;
297	      sourceTask.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
298	      sourceTask.dirty = true;
299	      // Mark subtasks too
300	      for (const sub of sourceTask.subtasks) {
301	        sub.status = 'deferred';
302	        sub.isStrikethrough = true;
303	        sub.forward = { path: `notes/daily/${targetDate}`, alias: targetDate.slice(5) };
304	        sub.dirty = true;
305	      }
306	    }
307	    writeNote(path, serialize(mutableSource));
308	
309	    // Add task to target with history link
310	    let mutableTarget = parse(targetContent);
311	    const newTask: Task = {
312	      type: 'task',
313	      line: 0,
314	      raw: '',
315	      dirty: true,
316	      id: nextId,
317	      status: task.status,
318	      content: taskText,
319	      subtasks: [],
320	      indent: 0,
321	      links: [...task.links],
322	      history: [...task.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
323	      isLabel: task.isLabel,
324	      isStrikethrough: false,
325	    };
326	
327	    // Add subtasks
328	    let subCounter = 1;
329	    for (const sub of task.subtasks) {
330	      if (sub.status !== 'done' && sub.status !== 'cancelled') {
331	        newTask.subtasks.push({
332	          type: 'task',
333	          line: 0,
334	          raw: '',
335	          dirty: true,
336	          id: `${nextId}.${subCounter++}`,
337	          status: sub.status,
338	          content: sub.content,
339	          subtasks: [],
340	          indent: 2,
341	          links: [...sub.links],
342	          history: [...sub.history, { path: `notes/daily/${date}`, alias: date.slice(5) }],
343	          isLabel: sub.isLabel,
344	          isStrikethrough: false,
345	        });
346	      }
347	    }
348	
349	    // Insert into target Tasks section
350	    let targetTasksSection = mutableTarget.sections.find(s => s.heading.toLowerCase() === 'tasks');
351	    if (!targetTasksSection) {
352	      targetTasksSection = { heading: 'Tasks', level: 2, body: [], line: 0, raw: '## Tasks' };
353	      mutableTarget.sections.push(targetTasksSection);
354	    }
355	    let insertIdx = targetTasksSection.body.length;
356	    while (insertIdx > 0 && targetTasksSection.body[insertIdx - 1].type === 'blank') insertIdx--;
357	    targetTasksSection.body.splice(insertIdx, 0, newTask);
358	
359	    writeNote(targetPath, serialize(mutableTarget));
360	    return `Moved task "${args.task}" from ${date} to ${targetDate} as [${nextId}].`;
361	  }
362	
363	  return `Specify to_top, under, or to_date to move the task.`;
364	}
