366	// ── Link/unlink docs to tasks ──────────────────────────────────────────
367	
368	export function linkDoc(args: { date?: string; task: string; doc: string }): string {
369	  const date = parseDate(args.date);
370	  const path = ensureDaily(date);
371	  const content = readNote(path)!;
372	  const doc = parse(content);
373	
374	  // Normalize doc path
375	  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");
376	
377	  const task = findTaskByQuery(doc, args.task);
378	  if (!task) return `Task "${args.task}" not found in ${date}.`;
379	
380	  // Check if already linked
381	  if (task.links.some(l => l.path === docPath)) {
382	    return `Doc already linked to task [${args.task}] in ${date}: ${docPath}`;
383	  }
384	
385	  const updated = omLinkDoc(doc, task.id, docPath);
386	  writeNote(path, serialize(updated));
387	  return confirm(`Doc linked to task [${args.task}]`, date, docPath);
388	}
389	
390	export function unlinkDoc(args: { date?: string; task: string; doc: string }): string {
391	  const date = parseDate(args.date);
392	  const path = `daily/${date}.md`;
393	  if (!noteExists(path)) return notFound("daily note", date);
394	  const content = readNote(path)!;
395	  const doc = parse(content);
396	
397	  const docPath = args.doc.replace(/\.md$/, "").replace(/^vault\//, "");
398	
399	  const task = findTaskByQuery(doc, args.task);
400	  if (!task) return `Task "${args.task}" not found in ${date}.`;
401	
402	  if (!task.links.some(l => l.path === docPath)) {
403	    return `Doc not linked to task [${args.task}] in ${date}: ${docPath}`;
404	  }
405	
406	  const updated = omUnlinkDoc(doc, task.id, docPath);
407	  writeNote(path, serialize(updated));
408	  return confirm(`Doc unlinked from task [${args.task}]`, date, docPath);
409	}
