411	// ── Status groups for filtering ─────────────────────────────────────────
412	
413	const STATUS_GROUPS: Record<string, string[]> = {
414	  open: [" ", "/", "!", "?"],
415	  done: ["x", "X", ">", "-"],
416	  todo: [" "],
417	  in_progress: ["/"],
418	  urgent: ["!"],
419	  question: ["?"],
420	  completed: ["x", "X"],
421	  deferred: [">"],
422	  cancelled: ["-"],
423	};
424	
425	// ── List tasks (section only — no full note) ────────────────────────────
426	
427	export function listTasks(args: { date?: string; filter?: string; search?: string }): string {
428	  const date = parseDate(args.date);
429	  const path = `daily/${date}.md`;
430	  if (!noteExists(path)) return notFound("daily note", date);
431	  const content = readNote(path)!;
432	  const doc = parse(content);
433	  const section = omFindSection(doc, 'Tasks');
434	  if (!section || section.body.every(n => n.type === 'blank')) return notFound("tasks", date);
435	
436	  let body = sectionBodyText(section);
437	
438	  if (!body) return notFound("tasks", date);
439	
440	  // Default to "open" unless explicitly "all" or no filter needed
441	  const effectiveFilter = args.filter === "all" ? undefined : (args.filter || (args.search ? undefined : "open"));
442	
443	  // Apply filters if provided
444	  if (effectiveFilter || args.search) {
445	    const allowedMarkers = effectiveFilter ? STATUS_GROUPS[effectiveFilter] : null;
446	    const searchLower = args.search?.toLowerCase();
447	    const bodyLines = body.split(/\r?\n/);
448	    const filtered: string[] = [];
449	    const added = new Set<number>();
450	
451	    for (let i = 0; i < bodyLines.length; i++) {
452	      if (added.has(i)) continue;
453	      const line = bodyLines[i];
454	
455	      const isLabel = line.match(/^\s*- \*\*\[/);
456	      if (isLabel) {
457	        let hasMatch = false;
458	        for (let j = i + 1; j < bodyLines.length; j++) {
459	          if (!bodyLines[j].match(/^\s+- /)) break;
460	          if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
461	            hasMatch = true;
462	            break;
463	          }
464	        }
465	        if (hasMatch) {
466	          filtered.push(line);
467	          added.add(i);
468	          for (let j = i + 1; j < bodyLines.length; j++) {
469	            if (!bodyLines[j].match(/^\s+- /)) break;
470	            if (lineMatchesFilter(bodyLines[j], allowedMarkers, searchLower)) {
471	              filtered.push(bodyLines[j]);
472	              added.add(j);
473	            }
474	          }
475	        }
476	        continue;
477	      }
478	
479	      const isSub = line.match(/^\s+- /);
480	      if (isSub) continue;
481	
482	      if (lineMatchesFilter(line, allowedMarkers, searchLower)) {
483	        filtered.push(line);
484	        added.add(i);
485	        for (let j = i + 1; j < bodyLines.length; j++) {
486	          if (!bodyLines[j].match(/^\s+- /)) break;
487	          filtered.push(bodyLines[j]);
488	          added.add(j);
489	        }
490	      }
491	    }
492	
493	    if (filtered.length === 0) {
494	      const parts: string[] = [];
495	      if (effectiveFilter) parts.push(`status "${effectiveFilter}"`);
496	      if (args.search) parts.push(`"${args.search}"`);
497	      return `No tasks matching ${parts.join(" and ")} in ${date}.`;
498	    }
499	
500	    body = filtered.join("\n");
501	  }
502	
503	  const c = countItems(content);
504	  const showFilter = effectiveFilter && effectiveFilter !== "open";
505	  const label = showFilter || args.search
506	    ? `${counts(date, c)} (filtered: ${showFilter ? effectiveFilter : ""}${showFilter && args.search ? " + " : ""}${args.search ? `"${args.search}"` : ""})`
507	    : counts(date, c);
508	  return `${label}\n\n${formatTaskLines(body)}`;
509	}
510	
511	function lineMatchesFilter(line: string, allowedMarkers: string[] | null, searchLower?: string): boolean {
512	  const markerMatch = line.match(/^\s*- \[(.)\]/);
513	  if (!markerMatch) return false;
514	  if (allowedMarkers && !allowedMarkers.includes(markerMatch[1])) return false;
515	  if (searchLower && !line.toLowerCase().includes(searchLower)) return false;
516	  return true;
517	}
518	
519	// ── Summary (lightweight counts) ────────────────────────────────────────
520	
521	export function taskSummary(args: { date?: string }): string {
522	  const date = parseDate(args.date);
523	  const path = `daily/${date}.md`;
524	  if (!noteExists(path)) return notFound("daily note", date);
525	  const content = readNote(path)!;
526	  const c = countItems(content);
527	  return counts(date, c);
528	}
