530	// ── Tool definition ─────────────────────────────────────────────────────
531	
532	export const toolDef: ToolDefinition = {
533	  name: "obsidian_tasks",
534	  description:
535	    "Task operations on daily notes. Commands: add, complete, status, edit, move, link, unlink, list (tasks section only), summary (counts only).",
536	  inputSchema: z.object({
537	    command: z.enum(["add", "complete", "status", "edit", "move", "link", "unlink", "list", "summary"])
538	      .describe("Task command to run"),
539	    date: z.string().optional().describe("Target date (YYYY-MM-DD, 'tomorrow', 'yesterday')"),
540	    content: z.string().optional().describe("Task text (for add)"),
541	    parent: z.string().optional().describe("Parent task number for sub-tasks (for add)"),
542	    task: z.string().optional().describe("Task number or text to match"),
543	    status: z.string().optional().describe("Task status: in_progress, deferred, cancelled, urgent, question, done, todo"),
544	    text: z.string().optional().describe("New text (for edit)"),
545	    doc: z.string().optional().describe("Document path to link/unlink (for link, unlink)"),
546	    to_date: z.string().optional().describe("Move task to this date"),
547	    under: z.string().optional().describe("Nest task under this parent number"),
548	    to_top: z.boolean().optional().describe("Promote sub-task to top-level"),
549	    filter: z.string().optional().describe("Filter tasks by status: all (show everything), open (default), done, todo, in_progress, urgent, question, completed, deferred, cancelled"),
550	    search: z.string().optional().describe("Filter tasks by text search (case-insensitive)"),
551	  }),
552	  tags: ["vault", "obsidian"],
553	  execute: async (args: any) => {
