import { existsSync, readdirSync, statSync } from "fs";
import { join, resolve } from "path";

const aliases: Record<string, string> = {
  research: "notebooklm",
  db: "brain",
  phonetics: "lyrics-analyze",
};

// Project root = one level up from src/
const projectRoot = resolve(import.meta.dir, "..");
const toolsDir = join(projectRoot, "src", "tools");

function discoverTools(): { name: string; path: string }[] {
  const tools: { name: string; path: string }[] = [];
  const seen = new Set<string>();

  if (!existsSync(toolsDir)) return tools;

  const entries = readdirSync(toolsDir).sort();

  for (const entry of entries) {
    const fullPath = join(toolsDir, entry);
    const stat = statSync(fullPath);

    if (stat.isDirectory()) {
      const indexPath = join(fullPath, "index.ts");
      if (existsSync(indexPath) && !seen.has(entry)) {
        tools.push({ name: entry, path: join("src", "tools", entry, "index.ts") });
        seen.add(entry);
      }
    } else if (entry.endsWith(".ts") && !entry.endsWith(".test.ts")) {
      const name = entry.slice(0, -3);
      if (!seen.has(name)) {
        tools.push({ name, path: join("src", "tools", entry) });
        seen.add(name);
      }
    }
  }

  return tools;
}

function printList(): void {
  const tools = discoverTools();
  console.log("Available tools:");
  for (const tool of tools) {
    // Normalize path separators to forward slash for display
    const displayPath = tool.path.replace(/\\/g, "/");
    console.log(`  ${tool.name.padEnd(20)}${displayPath}`);
  }
  console.log("");
  console.log("Aliases:");
  for (const [alias, target] of Object.entries(aliases)) {
    console.log(`  ${alias}  →  ${target}`);
  }
}

function printUsage(): void {
  console.log("Usage: bun run tool <name> [args]");
  console.log("       bun run tool --list");
  console.log("       bun run tool --help");
}

function resolveTool(name: string): string | null {
  if (/[\/\\]|\.\./.test(name)) return null;
  const resolved = aliases[name] ?? name;

  const filePath = join(toolsDir, `${resolved}.ts`);
  if (existsSync(filePath)) {
    return join("src", "tools", `${resolved}.ts`);
  }

  const indexPath = join(toolsDir, resolved, "index.ts");
  if (existsSync(indexPath)) {
    return join("src", "tools", resolved, "index.ts");
  }

  return null;
}

// Parse argv: Bun.argv = ["bun", "src/tool.ts", ...userArgs]
const userArgs = Bun.argv.slice(2);

if (userArgs.length === 0 || userArgs[0] === "--help") {
  printUsage();
  process.exit(0);
}

if (userArgs[0] === "--list") {
  printList();
  process.exit(0);
}

const toolName = userArgs[0];
const toolPath = resolveTool(toolName);

if (!toolPath) {
  process.stderr.write(`Unknown tool: ${toolName}\n`);
  process.exit(1);
}

// Normalize to forward slashes for cross-platform consistency
const normalizedPath = toolPath.replace(/\\/g, "/");

const proc = Bun.spawn(["bun", normalizedPath, ...userArgs.slice(1)], {
  stdio: ["inherit", "inherit", "inherit"],
  cwd: projectRoot,
});

await proc.exited;
process.exit(proc.exitCode ?? 1);

