// Sync (Obsidian Sync operations)
export { daemonStart, daemonStop, daemonStatus, daemonRestart, daemonLogs } from "./sync.js";

// ── CLI router ──────────────────────────────────────────────────────────────
// Dispatches `bun src/tools/obsidian/index.ts <subcommand> [args]` to the
// correct sub-module so `bun run tool obsidian tasks list` works.

if (import.meta.main) {
  const args = process.argv.slice(2);
  const subcommand = args[0];

  const submodules: Record<string, string> = {
    tasks: "tasks.ts",
    sections: "sections.ts",
    daily: "daily.ts",
    meeting: "meeting.ts",
    search: "search.ts",
    summaries: "summaries.ts",
    sync: "sync.ts",
  };

  if (!subcommand || subcommand === "--help") {
    console.log("Usage: bun run tool obsidian <subcommand> [args]");
    console.log("");
    console.log("Subcommands:");
    for (const name of Object.keys(submodules)) {
      console.log(`  ${name}`);
    }
    console.log("");
    console.log("Run `bun run tool obsidian <subcommand> --help` for subcommand usage.");
    process.exit(0);
  }

  const file = submodules[subcommand];
  if (!file) {
    process.stderr.write(`Unknown subcommand: ${subcommand}\nRun with --help for usage.\n`);
    process.exit(1);
  }

  const { resolve, dirname } = await import("path");
  const subPath = resolve(dirname(import.meta.path), file);
  const subArgs = args.slice(1);

  const proc = Bun.spawn(["bun", subPath, ...subArgs], {
    stdio: ["inherit", "inherit", "inherit"],
    cwd: process.cwd(),
  });

  await proc.exited;
  process.exit(proc.exitCode ?? 1);
}

